import{_ as a,o as i,c as t,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"MomCare App QA Checklist","description":"","frontmatter":{"title":"MomCare App QA Checklist","date":"2026-05-17T00:00:00.000Z","type":"qa-checklist","app":"MomCare","status":"draft","tags":["momcare","qa","testing","checklist","obsidian"]},"headers":[],"relativePath":"10_core/50_operations/40_dev_testing/momscare/2026-05-17_momcare_app_qa_checklist.md","filePath":"10_core/50_operations/40_dev_testing/momscare/2026-05-17_momcare_app_qa_checklist.md"}'),l={name:"10_core/50_operations/40_dev_testing/momscare/2026-05-17_momcare_app_qa_checklist.md"};function s(o,e,n,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="momcare-app-qa-checklist" tabindex="-1">MomCare App QA Checklist <a class="header-anchor" href="#momcare-app-qa-checklist" aria-label="Permalink to &quot;MomCare App QA Checklist&quot;">​</a></h1><p><strong>Date Tested:</strong><br><strong>Tester:</strong> Cody<br><strong>App Version / Branch:</strong><br><strong>Device:</strong><br><strong>Browser / OS:</strong><br><strong>Environment:</strong> Local / Dev / Production</p><hr><h2 id="_1-app-startup-access" tabindex="-1">1. App Startup &amp; Access <a class="header-anchor" href="#_1-app-startup-access" aria-label="Permalink to &quot;1. App Startup &amp; Access&quot;">​</a></h2><ul><li>[ ] App opens without crashing.</li><li>[ ] No console errors appear on initial load.</li><li>[ ] App loads within a reasonable time.</li><li>[ ] User can access the main dashboard/home screen.</li><li>[ ] App works on desktop.</li><li>[ ] App works on mobile.</li><li>[ ] Layout does not break on small screens.</li><li>[ ] Navigation/menu is visible and usable.</li><li>[ ] Page refresh does not break the app.</li><li>[ ] Direct URL navigation works if applicable.</li></ul><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_2-main-dashboard" tabindex="-1">2. Main Dashboard <a class="header-anchor" href="#_2-main-dashboard" aria-label="Permalink to &quot;2. Main Dashboard&quot;">​</a></h2><ul><li>[ ] Dashboard clearly shows today’s care status.</li><li>[ ] Dashboard shows the current date.</li><li>[ ] Dashboard shows the caregiver name or active user if applicable.</li><li>[ ] Dashboard shows urgent/open care items.</li><li>[ ] Dashboard shows recent logs or last update.</li><li>[ ] Dashboard shows upcoming appointments or reminders.</li><li>[ ] Dashboard separates urgent from routine.</li><li>[ ] Dashboard is readable at a glance.</li><li>[ ] Dashboard does not feel cluttered.</li><li>[ ] Dashboard has clear buttons for adding new entries.</li></ul><h3 id="notes-1" tabindex="-1">Notes <a class="header-anchor" href="#notes-1" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_3-daily-care-log" tabindex="-1">3. Daily Care Log <a class="header-anchor" href="#_3-daily-care-log" aria-label="Permalink to &quot;3. Daily Care Log&quot;">​</a></h2><ul><li>[ ] User can create a new daily care log.</li><li>[ ] Date defaults to today.</li><li>[ ] User can edit the date if needed.</li><li>[ ] User can add morning notes.</li><li>[ ] User can add afternoon notes.</li><li>[ ] User can add evening notes.</li><li>[ ] User can save partial entries.</li><li>[ ] User can edit saved entries.</li><li>[ ] User can delete or archive incorrect entries.</li><li>[ ] App confirms when an entry is saved.</li><li>[ ] App warns before deleting.</li><li>[ ] Saved logs appear in the correct order.</li><li>[ ] Logs do not duplicate after saving.</li><li>[ ] Required fields are clear.</li><li>[ ] Optional fields are clearly optional.</li></ul><h3 id="notes-2" tabindex="-1">Notes <a class="header-anchor" href="#notes-2" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_4-vitals-tracking" tabindex="-1">4. Vitals Tracking <a class="header-anchor" href="#_4-vitals-tracking" aria-label="Permalink to &quot;4. Vitals Tracking&quot;">​</a></h2><ul><li>[ ] User can enter blood pressure.</li><li>[ ] Blood pressure format is easy to understand.</li><li>[ ] User can enter heart rate.</li><li>[ ] User can enter oxygen saturation.</li><li>[ ] User can enter temperature.</li><li>[ ] User can enter glucose.</li><li>[ ] User can enter pain level.</li><li>[ ] User can mark whether vitals were taken before or after eating.</li><li>[ ] User can add notes about symptoms or context.</li><li>[ ] App handles missing vitals without crashing.</li><li>[ ] App flags unusual values visually, if that feature exists.</li><li>[ ] App does not provide unsafe medical advice.</li><li>[ ] Vitals save correctly.</li><li>[ ] Vitals display correctly in history.</li><li>[ ] Vitals can be edited if entered wrong.</li><li>[ ] Units are clear: °F, bpm, %, mg/dL, etc.</li></ul><h3 id="notes-3" tabindex="-1">Notes <a class="header-anchor" href="#notes-3" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_5-oxygen-breathing-equipment-tracking" tabindex="-1">5. Oxygen / Breathing Equipment Tracking <a class="header-anchor" href="#_5-oxygen-breathing-equipment-tracking" aria-label="Permalink to &quot;5. Oxygen / Breathing Equipment Tracking&quot;">​</a></h2><ul><li>[ ] User can record oxygen tubing check.</li><li>[ ] User can record whether tubing has kinks.</li><li>[ ] User can record oxygen tank count.</li><li>[ ] User can record full tanks.</li><li>[ ] User can record empty tanks.</li><li>[ ] User can record concentrator status if applicable.</li><li>[ ] User can record charger/battery status.</li><li>[ ] User can mark needs reorder.</li><li>[ ] App clearly shows low oxygen supply alerts if applicable.</li><li>[ ] App allows caregiver notes for breathing treatments.</li><li>[ ] App handles not checked without treating it as failure.</li></ul><h3 id="notes-4" tabindex="-1">Notes <a class="header-anchor" href="#notes-4" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_6-meals-food-intake" tabindex="-1">6. Meals / Food / Intake <a class="header-anchor" href="#_6-meals-food-intake" aria-label="Permalink to &quot;6. Meals / Food / Intake&quot;">​</a></h2><ul><li>[ ] User can log breakfast.</li><li>[ ] User can log lunch.</li><li>[ ] User can log dinner.</li><li>[ ] User can log snacks.</li><li>[ ] User can log drinks.</li><li>[ ] User can mark appetite: good / okay / poor.</li><li>[ ] User can note food reactions or stomach issues.</li><li>[ ] User can mark after eating when logging glucose.</li><li>[ ] Food entries save correctly.</li><li>[ ] Food history is easy to review.</li><li>[ ] App does not make the meal log too complicated.</li></ul><h3 id="notes-5" tabindex="-1">Notes <a class="header-anchor" href="#notes-5" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_7-hygiene-bathroom-personal-care" tabindex="-1">7. Hygiene / Bathroom / Personal Care <a class="header-anchor" href="#_7-hygiene-bathroom-personal-care" aria-label="Permalink to &quot;7. Hygiene / Bathroom / Personal Care&quot;">​</a></h2><ul><li>[ ] User can log bathroom assistance.</li><li>[ ] User can log hygiene assistance.</li><li>[ ] User can use respectful wording, not demeaning labels.</li><li>[ ] User can log wipes/cleaning.</li><li>[ ] User can log clothing or bedding change if applicable.</li><li>[ ] User can mark not needed.</li><li>[ ] User can add private caregiver notes.</li><li>[ ] Entries are easy to complete quickly.</li><li>[ ] App avoids making routine care feel overly clinical.</li></ul><h3 id="notes-6" tabindex="-1">Notes <a class="header-anchor" href="#notes-6" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_8-safety-scan" tabindex="-1">8. Safety Scan <a class="header-anchor" href="#_8-safety-scan" aria-label="Permalink to &quot;8. Safety Scan&quot;">​</a></h2><ul><li>[ ] User can complete a daily safety scan.</li><li>[ ] Checklist includes kitchen.</li><li>[ ] Checklist includes living room.</li><li>[ ] Checklist includes bathroom path.</li><li>[ ] Checklist includes bedroom path.</li><li>[ ] Checklist includes oxygen tubing.</li><li>[ ] Checklist includes fall hazards.</li><li>[ ] Checklist includes clutter/laundry.</li><li>[ ] Checklist includes floor hazards.</li><li>[ ] User can mark each area as clear / needs attention / not checked.</li><li>[ ] User can add notes.</li><li>[ ] User can create follow-up tasks from safety issues.</li><li>[ ] Safety scan saves to the daily log.</li></ul><h3 id="notes-7" tabindex="-1">Notes <a class="header-anchor" href="#notes-7" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_9-tasks-follow-ups" tabindex="-1">9. Tasks &amp; Follow-Ups <a class="header-anchor" href="#_9-tasks-follow-ups" aria-label="Permalink to &quot;9. Tasks &amp; Follow-Ups&quot;">​</a></h2><ul><li>[ ] User can create a task.</li><li>[ ] User can assign a task category.</li><li>[ ] User can set priority.</li><li>[ ] User can set due date.</li><li>[ ] User can mark task as done.</li><li>[ ] User can edit task.</li><li>[ ] User can delete/archive task.</li><li>[ ] Tasks can be linked to appointments, care logs, or provider instructions.</li><li>[ ] Open tasks are visible on dashboard.</li><li>[ ] Completed tasks are still accessible in history.</li><li>[ ] App separates care tasks from admin tasks.</li><li>[ ] App separates urgent tasks from routine follow-ups.</li></ul><h3 id="notes-8" tabindex="-1">Notes <a class="header-anchor" href="#notes-8" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_10-appointments" tabindex="-1">10. Appointments <a class="header-anchor" href="#_10-appointments" aria-label="Permalink to &quot;10. Appointments&quot;">​</a></h2><ul><li>[ ] User can add an appointment.</li><li>[ ] User can enter appointment type.</li><li>[ ] User can enter provider/location.</li><li>[ ] User can enter date and time.</li><li>[ ] User can add prep notes.</li><li>[ ] User can add transportation notes.</li><li>[ ] User can add follow-up notes after appointment.</li><li>[ ] Appointment appears on dashboard or calendar view.</li><li>[ ] Appointment can be edited.</li><li>[ ] Appointment can be canceled/archived.</li><li>[ ] Appointment does not disappear after the date passes.</li><li>[ ] Past appointments are easy to review.</li></ul><h3 id="notes-9" tabindex="-1">Notes <a class="header-anchor" href="#notes-9" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_11-provider-mychart-task-capture" tabindex="-1">11. Provider / MyChart Task Capture <a class="header-anchor" href="#_11-provider-mychart-task-capture" aria-label="Permalink to &quot;11. Provider / MyChart Task Capture&quot;">​</a></h2><ul><li>[ ] User can enter provider task manually.</li><li>[ ] User can paste copied MyChart/task text.</li><li>[ ] User can upload or attach screenshot/photo if supported.</li><li>[ ] User can categorize provider tasks.</li><li>[ ] User can mark task source: MyChart / provider / phone call / discharge papers / other.</li><li>[ ] User can mark urgency.</li><li>[ ] User can link provider task to Mom’s care record.</li><li>[ ] User can mark provider task as scheduled.</li><li>[ ] User can mark provider task as completed.</li><li>[ ] App preserves original text/source notes.</li></ul><h3 id="notes-10" tabindex="-1">Notes <a class="header-anchor" href="#notes-10" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_12-voice-quick-capture" tabindex="-1">12. Voice / Quick Capture <a class="header-anchor" href="#_12-voice-quick-capture" aria-label="Permalink to &quot;12. Voice / Quick Capture&quot;">​</a></h2><ul><li>[ ] User can quickly add a note without filling out a huge form.</li><li>[ ] User can capture messy real-life notes and clean them later.</li><li>[ ] User can add quick note from dashboard.</li><li>[ ] Quick notes are timestamped.</li><li>[ ] Quick notes can be converted into tasks.</li><li>[ ] Quick notes can be converted into care log entries.</li><li>[ ] Quick notes can be edited after capture.</li><li>[ ] App does not force perfection during capture.</li></ul><h3 id="notes-11" tabindex="-1">Notes <a class="header-anchor" href="#notes-11" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_13-search-history" tabindex="-1">13. Search &amp; History <a class="header-anchor" href="#_13-search-history" aria-label="Permalink to &quot;13. Search &amp; History&quot;">​</a></h2><ul><li>[ ] User can search care logs.</li><li>[ ] User can search tasks.</li><li>[ ] User can search appointments.</li><li>[ ] User can filter by date.</li><li>[ ] User can filter by category.</li><li>[ ] User can filter by status.</li><li>[ ] User can find a previous day’s log quickly.</li><li>[ ] User can review trends without hunting.</li><li>[ ] Search results are clear and readable.</li></ul><h3 id="notes-12" tabindex="-1">Notes <a class="header-anchor" href="#notes-12" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_14-reports-export" tabindex="-1">14. Reports / Export <a class="header-anchor" href="#_14-reports-export" aria-label="Permalink to &quot;14. Reports / Export&quot;">​</a></h2><ul><li>[ ] User can generate a daily summary.</li><li>[ ] User can generate a weekly summary.</li><li>[ ] User can generate an appointment prep summary.</li><li>[ ] User can export to Markdown.</li><li>[ ] User can export to PDF if supported.</li><li>[ ] Export includes date range.</li><li>[ ] Export includes vitals.</li><li>[ ] Export includes tasks.</li><li>[ ] Export includes appointments.</li><li>[ ] Export includes caregiver notes.</li><li>[ ] Export avoids clutter.</li><li>[ ] Export is readable by a provider/family member.</li><li>[ ] Export does not expose unnecessary private notes unless selected.</li></ul><h3 id="notes-13" tabindex="-1">Notes <a class="header-anchor" href="#notes-13" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_15-data-integrity" tabindex="-1">15. Data Integrity <a class="header-anchor" href="#_15-data-integrity" aria-label="Permalink to &quot;15. Data Integrity&quot;">​</a></h2><ul><li>[ ] Saved data persists after refresh.</li><li>[ ] Saved data persists after closing/reopening app.</li><li>[ ] Editing one entry does not change unrelated entries.</li><li>[ ] Deleting one entry does not delete unrelated data.</li><li>[ ] Duplicate records are not created accidentally.</li><li>[ ] Dates are stored correctly.</li><li>[ ] Times are stored correctly.</li><li>[ ] Empty fields do not break the app.</li><li>[ ] Special characters do not break saving.</li><li>[ ] Long notes do not break layout or database save.</li><li>[ ] App handles connection/database errors gracefully.</li></ul><h3 id="notes-14" tabindex="-1">Notes <a class="header-anchor" href="#notes-14" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_16-error-handling" tabindex="-1">16. Error Handling <a class="header-anchor" href="#_16-error-handling" aria-label="Permalink to &quot;16. Error Handling&quot;">​</a></h2><ul><li>[ ] App shows useful error messages.</li><li>[ ] Error messages explain what went wrong.</li><li>[ ] Error messages tell user what to do next.</li><li>[ ] App does not expose raw technical errors to normal users unless in dev mode.</li><li>[ ] Failed saves are clearly shown.</li><li>[ ] User does not think something saved when it failed.</li><li>[ ] App protects against accidental duplicate submissions.</li><li>[ ] App handles invalid input without crashing.</li></ul><h3 id="notes-15" tabindex="-1">Notes <a class="header-anchor" href="#notes-15" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_17-ui-ux-sanity-check" tabindex="-1">17. UI / UX Sanity Check <a class="header-anchor" href="#_17-ui-ux-sanity-check" aria-label="Permalink to &quot;17. UI / UX Sanity Check&quot;">​</a></h2><ul><li>[ ] Buttons are clearly labeled.</li><li>[ ] Forms are not too long.</li><li>[ ] Most common actions are easy to reach.</li><li>[ ] Text is readable.</li><li>[ ] Spacing is clean.</li><li>[ ] Important information is visually prioritized.</li><li>[ ] Urgent items stand out.</li><li>[ ] Routine items do not scream for attention.</li><li>[ ] Mobile layout is usable one-handed.</li><li>[ ] The app feels calm, not chaotic.</li><li>[ ] The app supports caregiver reality, not fantasy-office workflow.</li></ul><h3 id="notes-16" tabindex="-1">Notes <a class="header-anchor" href="#notes-16" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_18-accessibility-low-energy-use" tabindex="-1">18. Accessibility &amp; Low-Energy Use <a class="header-anchor" href="#_18-accessibility-low-energy-use" aria-label="Permalink to &quot;18. Accessibility &amp; Low-Energy Use&quot;">​</a></h2><ul><li>[ ] App can be used when caregiver is tired.</li><li>[ ] App can be used quickly during interruptions.</li><li>[ ] Labels are plain language.</li><li>[ ] Click/tap targets are large enough.</li><li>[ ] Color is not the only way status is shown.</li><li>[ ] Important items have text labels.</li><li>[ ] Forms can be completed in under 1–2 minutes where possible.</li><li>[ ] App does not require perfect typing.</li><li>[ ] App supports capture now, organize later.</li></ul><h3 id="notes-17" tabindex="-1">Notes <a class="header-anchor" href="#notes-17" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_19-privacy-permissions" tabindex="-1">19. Privacy / Permissions <a class="header-anchor" href="#_19-privacy-permissions" aria-label="Permalink to &quot;19. Privacy / Permissions&quot;">​</a></h2><ul><li>[ ] Sensitive notes are not exposed on public screens.</li><li>[ ] Export does not include private notes by default.</li><li>[ ] User roles/permissions work if applicable.</li><li>[ ] Family-facing view is separate from caregiver/admin view if applicable.</li><li>[ ] App does not leak private data in console logs.</li><li>[ ] App does not store unnecessary sensitive data.</li><li>[ ] Backups/export files are named clearly.</li></ul><h3 id="notes-18" tabindex="-1">Notes <a class="header-anchor" href="#notes-18" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h2 id="_20-final-retest-checklist" tabindex="-1">20. Final Retest Checklist <a class="header-anchor" href="#_20-final-retest-checklist" aria-label="Permalink to &quot;20. Final Retest Checklist&quot;">​</a></h2><ul><li>[ ] App still starts.</li><li>[ ] Dashboard still loads.</li><li>[ ] Daily log still saves.</li><li>[ ] Vitals still save.</li><li>[ ] Tasks still save.</li><li>[ ] Appointments still save.</li><li>[ ] Search/history still works.</li><li>[ ] No new console errors.</li><li>[ ] Previous bug is fixed.</li><li>[ ] No obvious new bug was introduced.</li><li>[ ] Updated behavior matches the requested fix.</li><li>[ ] Documentation/notes were updated if behavior changed.</li></ul><h3 id="notes-19" tabindex="-1">Notes <a class="header-anchor" href="#notes-19" aria-label="Permalink to &quot;Notes&quot;">​</a></h3><hr><h1 id="_2026-05-18-initial-smoke-pass" tabindex="-1">2026-05-18 Initial Smoke Pass <a class="header-anchor" href="#_2026-05-18-initial-smoke-pass" aria-label="Permalink to &quot;2026-05-18 Initial Smoke Pass&quot;">​</a></h1><p><strong>Environment:</strong> Local dev<br><strong>URL:</strong> <code>http://127.0.0.1:5173</code><br><strong>Build:</strong> Passed via <code>npm run build</code><br><strong>Direct route probe:</strong> <code>/</code>, <code>/vitals</code>, <code>/tasks</code>, and <code>/admin/dashboard</code> all returned HTTP 200 in local dev<br><strong>Rendered browser validation:</strong> Blocked in this session because sandboxed Chromium/Edge headless runs failed with Windows access-denied profile/lock errors</p><h2 id="initial-findings" tabindex="-1">Initial Findings <a class="header-anchor" href="#initial-findings" aria-label="Permalink to &quot;Initial Findings&quot;">​</a></h2><h3 id="issue-001-readme-docs-alignment-is-not-usable-yet" tabindex="-1">ISSUE-001 - README/docs alignment is not usable yet <a class="header-anchor" href="#issue-001-readme-docs-alignment-is-not-usable-yet" aria-label="Permalink to &quot;ISSUE-001 - README/docs alignment is not usable yet&quot;">​</a></h3><p><strong>Priority:</strong> P1<br><strong>Type:</strong> Docs<br><strong>Area:</strong> Documentation<br><strong>Status:</strong> Open</p><p><strong>Expected</strong><br> MomsCare should have a real README that explains what the app is, how to run it locally, and how the caregiver/admin surfaces are organized.</p><p><strong>Actual</strong><br><code>apps/frontend/README.md</code> is still the stock Vite template, and the repo root <code>README.md</code> only contains <code># momscare</code>.</p><p><strong>Evidence</strong></p><ul><li><code>apps/frontend/README.md</code> contains generic Vite boilerplate</li><li><code>README.md</code> at the repo root is only a one-line placeholder</li></ul><p><strong>Impact</strong><br> Checklist items around local run instructions, troubleshooting, and current app behavior cannot be verified from the repo docs.</p><h3 id="issue-002-production-bundle-size-is-a-mobile-load-risk" tabindex="-1">ISSUE-002 - Production bundle size is a mobile-load risk <a class="header-anchor" href="#issue-002-production-bundle-size-is-a-mobile-load-risk" aria-label="Permalink to &quot;ISSUE-002 - Production bundle size is a mobile-load risk&quot;">​</a></h3><p><strong>Priority:</strong> P2<br><strong>Type:</strong> Performance<br><strong>Area:</strong> Startup / Mobile<br><strong>Status:</strong> Open</p><p><strong>Expected</strong><br> The caregiver app should stay lean enough that startup remains reasonable on phone-class devices.</p><p><strong>Actual</strong><br> The current production build emits a single <code>assets/index-DRPCntrI.js</code> bundle of about <code>1,386.74 kB</code>, and Vite warns that some chunks are larger than the recommended threshold.</p><p><strong>Evidence</strong><br> Observed in the local <code>npm run build</code> output during this smoke pass.</p><p><strong>Impact</strong><br> This does not fail the build, but it is a real risk against the checklist goals for quick loading and low-friction mobile use.</p><h1 id="issue-capture-template" tabindex="-1">Issue Capture Template <a class="header-anchor" href="#issue-capture-template" aria-label="Permalink to &quot;Issue Capture Template&quot;">​</a></h1><h2 id="issue-000-—-short-title" tabindex="-1">ISSUE-000 — Short Title <a class="header-anchor" href="#issue-000-—-short-title" aria-label="Permalink to &quot;ISSUE-000 — Short Title&quot;">​</a></h2><p><strong>Priority:</strong> P0 / P1 / P2 / P3<br><strong>Type:</strong> Bug / UI / UX / Data / Performance / Feature / Safety / Export<br><strong>Area:</strong> Dashboard / Daily Log / Vitals / Tasks / Appointments / Reports / Other<br><strong>Status:</strong> Open / Sent to AI / Fixed / Retest Needed / Closed / Deferred</p><h3 id="expected" tabindex="-1">Expected <a class="header-anchor" href="#expected" aria-label="Permalink to &quot;Expected&quot;">​</a></h3><p>What should have happened?</p><h3 id="actual" tabindex="-1">Actual <a class="header-anchor" href="#actual" aria-label="Permalink to &quot;Actual&quot;">​</a></h3><p>What happened instead?</p><h3 id="steps-to-reproduce" tabindex="-1">Steps to Reproduce <a class="header-anchor" href="#steps-to-reproduce" aria-label="Permalink to &quot;Steps to Reproduce&quot;">​</a></h3><ul><li>[ ] Step 1</li><li>[ ] Step 2</li><li>[ ] Step 3</li></ul><h3 id="evidence" tabindex="-1">Evidence <a class="header-anchor" href="#evidence" aria-label="Permalink to &quot;Evidence&quot;">​</a></h3><p>Screenshot, traceback, console error, wrong output, broken layout, etc.</p><h3 id="impact" tabindex="-1">Impact <a class="header-anchor" href="#impact" aria-label="Permalink to &quot;Impact&quot;">​</a></h3><p>Why does this matter?</p><h3 id="ai-instruction" tabindex="-1">AI Instruction <a class="header-anchor" href="#ai-instruction" aria-label="Permalink to &quot;AI Instruction&quot;">​</a></h3><p>Tell the AI exactly what to fix.</p><p>Example:</p><p>Fix the daily care log save behavior so entries persist after refresh. Do not change unrelated dashboard layout. Add a simple test or manual verification note showing that saved logs remain visible after reload.</p><hr><h1 id="ai-work-order-template" tabindex="-1">AI Work Order Template <a class="header-anchor" href="#ai-work-order-template" aria-label="Permalink to &quot;AI Work Order Template&quot;">​</a></h1><h2 id="momcare-app-work-order" tabindex="-1">MomCare App Work Order <a class="header-anchor" href="#momcare-app-work-order" aria-label="Permalink to &quot;MomCare App Work Order&quot;">​</a></h2><p><strong>Goal:</strong><br> Fix the highest-priority testing issues without redesigning unrelated parts of the app.</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ul><li>[ ] Fix P0 and P1 issues first.</li><li>[ ] Do not refactor unrelated architecture.</li><li>[ ] Do not rename fields unless required.</li><li>[ ] Preserve existing data structure unless a migration is necessary.</li><li>[ ] Keep forms fast and caregiver-friendly.</li><li>[ ] Update documentation if behavior changes.</li><li>[ ] Summarize files changed, fixes made, and how to retest.</li></ul><h2 id="issues-to-fix" tabindex="-1">Issues to Fix <a class="header-anchor" href="#issues-to-fix" aria-label="Permalink to &quot;Issues to Fix&quot;">​</a></h2><ul><li>[ ] ISSUE-001:</li><li>[ ] ISSUE-002:</li><li>[ ] ISSUE-003:</li></ul><h2 id="done-criteria" tabindex="-1">Done Criteria <a class="header-anchor" href="#done-criteria" aria-label="Permalink to &quot;Done Criteria&quot;">​</a></h2><ul><li>[ ] App launches.</li><li>[ ] Core care log flow works.</li><li>[ ] Vitals/tasks/appointments save correctly.</li><li>[ ] No new obvious console errors.</li><li>[ ] Retest checklist passes.</li></ul>',126)])])}const m=a(l,[["render",s]]);expo